// Provide the homepage URL — the workflow discovers all key pages automatically
// Slug is auto-generated from the domain name
return [{
  json: {
    url: 'https://example.com'
  }
}];

const links = ($json.links || []);
const baseUrl = $('Set Config').first().json.url.replace(/\/$/, '');

// Parse hostname with regex — URL constructor not available in n8n sandbox
const hostnameMatch = baseUrl.match(/^https?:\/\/([^\/]+)/);
const hostname = hostnameMatch ? hostnameMatch[1] : baseUrl;
const domain = hostname.replace(/^www\./, '');
const slug = domain.replace(/\.[^.]+$/, '').replace(/[^a-z0-9]+/gi, '-').toLowerCase();

const SKIP = /\/(blog|post|article|news|press|legal|privacy|terms|sitemap|tag|category|feed|wp-|admin|login|404|cdn|assets|uploads|media)\b/i;
const KEEP = /\/(about|service|contact|menu|pricing|location|team|appointment|booking|offer|product|portfolio|gallery)\b/i;

const filtered = [baseUrl];

for (const link of links) {
  if (filtered.length >= 8) break;
  const clean = link.replace(/\/$/, '');
  if (clean === baseUrl) continue;
  if (SKIP.test(clean)) continue;
  if (/sitemap/i.test(clean) || clean.match(/\.[a-z]{2,4}$/i)) continue;
  const pathMatch = clean.match(/^https?:\/\/[^\/]+(\/.*)?$/);
  const path = pathMatch ? (pathMatch[1] || '/') : '/';
  const depth = path.split('/').filter(Boolean).length;
  if (depth <= 2 && (KEEP.test(clean) || depth === 1)) {
    filtered.push(clean);
  }
}

return [{ json: { filtered_urls: filtered, homepage: baseUrl, slug } }];

const data = $json.data || {};
const url = data.metadata?.sourceURL || '(unknown url)';
const markdown = data.markdown || '(no content scraped)';
const title = data.metadata?.title || url;
const screenshot = data.screenshot || null;

// Extract real image URLs from markdown syntax before any filtering
const imgRegex = /!\[.*?\]\((https?:\/\/[^)\s]+)\)/g;
const imageUrls = [];
let m;
while ((m = imgRegex.exec(markdown)) !== null) {
  const src = m[1];
  if (
    !src.endsWith('.svg') &&
    !src.includes('data:') &&
    !src.includes('pixel') &&
    !src.includes('track') &&
    !src.includes('maps.googleapis.com') &&
    !src.includes('maps.gstatic.com') &&
    !src.includes('google.com/maps')
  ) {
    imageUrls.push(src);
  }
}

return [{ json: { formatted: `--- PAGE: ${title} | URL: ${url} ---\n\n${markdown}`, image_urls: imageUrls, screenshot } }];
